CREATE OR REPLACE FUNCTION func_calc_sfarsit_programare (
    p_id_serviciu    servicii.id_serviciu%TYPE,
    p_ora_programare DATE
) RETURN DATE AS
    v_durata NUMBER;
BEGIN
    SELECT
        durata_minute
    INTO v_durata
    FROM
        servicii
    WHERE
        id_serviciu = p_id_serviciu;

    RETURN p_ora_programare + v_durata / 1440;
EXCEPTION
    WHEN no_data_found THEN
        raise_application_error(-20001, 'Serviciul nu exista');
END;
