CREATE OR REPLACE FUNCTION func_stilistul_este_disponibil (
    p_id_stilist    IN stilisti.id_stilist%TYPE,
    p_id_serviciu   IN servicii.id_serviciu%TYPE,
    p_ora_start     IN DATE,
    p_id_programare IN programari.id_programare%TYPE
) RETURN BOOLEAN AS
    v_conflict    NUMBER;
    v_ora_sfarsit DATE;
BEGIN
    v_ora_sfarsit := func_calc_sfarsit_programare(p_id_serviciu, p_ora_start);
    SELECT
        COUNT(*)
    INTO v_conflict
    FROM
        programari
    WHERE
            id_stilist = p_id_stilist
        AND ora_programare < v_ora_sfarsit
        AND sfarsit_programare > p_ora_start
        AND ( p_id_programare IS NULL
              OR id_programare != p_id_programare );

    RETURN v_conflict = 0;
END;
/

