CREATE OR REPLACE TRIGGER Trg_Validare_programare 
    BEFORE INSERT OR UPDATE ON Programari 
    FOR EACH ROW 
BEGIN
	IF TO_CHAR(:new.ora_programare, 'DY') IN ('SAT','SUN') THEN
		RAISE_APPLICATION_ERROR(-20001,'Salonul este inchis in weekend');
	END IF;
	
	IF TO_NUMBER(TO_CHAR(:new.ora_programare,'HH24')) <8 OR 
	TO_NUMBER(TO_CHAR(:new.ora_programare, 'HH24')) >= 16 THEN
		RAISE_APPLICATION_ERROR(-20001,'Salonul este deschis intre 8:00 si 16:00');
	END IF;

	IF :new.ora_programare < SYSDATE THEN
		RAISE_APPLICATION_ERROR(-20001,'EROARE: Prog. nu poate fi facuta in trecut');
	END IF;

	IF :new.ora_programare > ADD_MONTHS(SYSDATE,12) THEN
		RAISE_APPLICATION_ERROR(-20001,'EROARE: Prog. nu poate fi facuta cu mai mult de 1 an inainte');
	END IF;
	

	:new.sfarsit_programare := Func_calc_sfarsit_programare(:new.id_serviciu,:new.ora_programare);
	
END; 
/

CREATE OR REPLACE PACKAGE Package_programari AS 
  FUNCTION calc_pret_client(
  p_id_client IN Programari.id_client%TYPE,
  p_zi IN DATE) RETURN NUMBER;
  
  FUNCTION Func_cauta_stilist_liber (
    p_id_serviciu IN Servicii.id_serviciu%type,
    p_ora_start IN DATE,
    p_id_stilist IN Stilisti.id_stilist%TYPE
    ) RETURN Stilisti.id_stilist%type; 
    
  PROCEDURE Proc_adauga_programare(
        p_id_client IN Programari.id_client%TYPE,
        p_id_serviciu IN Programari.id_serviciu%TYPE,
        p_ora_start IN DATE);
        
  PROCEDURE Proc_modifica_programare(
    p_id_programare IN Programari.id_programare%TYPE,
    p_ora_noua IN DATE);
    
  PROCEDURE Proc_sterge_prog_stilist(
    p_id_stilist IN Stilisti.id_stilist%TYPE,
    p_zi IN  DATE);
    
END Package_programari;
/

CREATE OR REPLACE PACKAGE BODY package_programari AS 

  ---------------------------------------------------
  -- Afiseaza pret client pentru o zi
  ---------------------------------------------------
    FUNCTION calc_pret_client (
        p_id_client IN programari.id_client%TYPE,
        p_zi        IN DATE
    ) RETURN NUMBER AS
        v_pret NUMBER := 0;
    BEGIN
        SELECT
            nvl(
                sum(s.pret),
                0
            )
        INTO v_pret
        FROM
            servicii   s,
            programari p
        WHERE
                s.id_serviciu = p.id_serviciu
            AND p.id_client = p_id_client
            AND trunc(p.ora_programare) = trunc(p_zi);

        RETURN v_pret;
    END;
  
  ---------------------------------------------------
  -- Cauta stilist liber pentru o programare
  ---------------------------------------------------
    FUNCTION func_cauta_stilist_liber (
        p_id_serviciu IN servicii.id_serviciu%TYPE,
        p_ora_start   IN DATE,
        p_id_stilist  IN stilisti.id_stilist%TYPE
    ) RETURN stilisti.id_stilist%TYPE AS

        v_id_returnat stilisti.id_stilist%TYPE;
        v_ora_sfarsit DATE;
        e_niciun_stilist EXCEPTION;
        CURSOR c_stilisti IS
        SELECT
            s.id_stilist,
            nvl(
                sum((p.sfarsit_programare - p.ora_programare) * 1440),
                0
            ) AS minute_lucrate
        FROM
            stilisti   s
            LEFT JOIN programari p ON s.id_stilist = p.id_stilist
                                      AND trunc(p.ora_programare) = trunc(p_ora_start)
        WHERE
            p_id_stilist IS NULL
            OR p_id_stilist != s.id_stilist
        GROUP BY
            s.id_stilist
        ORDER BY
            minute_lucrate ASC;

        v_rec         c_stilisti%rowtype;
    BEGIN
        v_ora_sfarsit := func_calc_sfarsit_programare(p_id_serviciu, p_ora_start);
        OPEN c_stilisti;
        LOOP
            FETCH c_stilisti INTO v_rec;
            EXIT WHEN c_stilisti%notfound;
            IF func_stilistul_este_disponibil(v_rec.id_stilist, p_id_serviciu, p_ora_start, NULL) THEN
                v_id_returnat := v_rec.id_stilist;
                EXIT;
            END IF;

        END LOOP;

        CLOSE c_stilisti;
        IF v_id_returnat IS NULL THEN
            RAISE e_niciun_stilist;
        END IF;
        RETURN v_id_returnat;
    EXCEPTION
        WHEN e_niciun_stilist THEN
            raise_application_error(-20001, 'Nu exista niciun stilist disponibil in acest interval');
    END;

  ---------------------------------------------------
  -- Adauga o programare
  ---------------------------------------------------
    PROCEDURE proc_adauga_programare (
        p_id_client   IN programari.id_client%TYPE,
        p_id_serviciu IN programari.id_serviciu%TYPE,
        p_ora_start   IN DATE
    ) AS
        v_id_stilist stilisti.id_stilist%TYPE;
        e_insert_esuat EXCEPTION;
    BEGIN
        v_id_stilist := func_cauta_stilist_liber(p_id_serviciu, p_ora_start, NULL);
        INSERT INTO programari (
            id_client,
            id_serviciu,
            id_stilist,
            ora_programare
        ) VALUES ( p_id_client,
                   p_id_serviciu,
                   v_id_stilist,
                   p_ora_start );

        COMMIT;
        dbms_output.put_line('Programare adaugata cu succes');
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            raise_application_error(-20001, sqlerrm);
    END proc_adauga_programare;
    
  ---------------------------------------------------
  -- Modifica ora unei programari
  ---------------------------------------------------
    PROCEDURE proc_modifica_programare (
        p_id_programare IN programari.id_programare%TYPE,
        p_ora_noua      IN DATE
    ) AS

        v_id_serviciu    programari.id_serviciu%TYPE;
        v_id_stilist     programari.id_stilist%TYPE;
        v_id_stilist_nou programari.id_stilist%TYPE;
    BEGIN
        SELECT
            id_serviciu,
            id_stilist
        INTO
            v_id_serviciu,
            v_id_stilist
        FROM
            programari
        WHERE
            id_programare = p_id_programare;

        IF func_stilistul_este_disponibil(v_id_stilist, v_id_serviciu, p_ora_noua, p_id_programare) THEN
            v_id_stilist_nou := v_id_stilist;
        ELSE
            v_id_stilist_nou := func_cauta_stilist_liber(v_id_serviciu, p_ora_noua, NULL);
            dbms_output.put_line('Stilistul s-a schimbat');
        END IF;

        UPDATE programari
        SET
            ora_programare = p_ora_noua,
            id_stilist = v_id_stilist_nou
        WHERE
            id_programare = p_id_programare;

        COMMIT;
        dbms_output.put_line('Programare modificata cu succes');
    EXCEPTION
        WHEN no_data_found THEN
            ROLLBACK;
            raise_application_error(-20001, 'Id programare invalid');
        WHEN OTHERS THEN
            ROLLBACK;
            raise_application_error(-20001, 'Eroare la modificare: ' || sqlerrm);
    END proc_modifica_programare; 
  
  ---------------------------------------------------
  -- Elimina programarile unui stilist intr-o zi
  ---------------------------------------------------
    PROCEDURE proc_sterge_prog_stilist (
        p_id_stilist IN stilisti.id_stilist%TYPE,
        p_zi         IN DATE
    ) AS

        v_stilist_nou stilisti.id_stilist%TYPE;
        CURSOR c_programari IS
        SELECT
            id_programare,
            id_serviciu,
            ora_programare
        FROM
            programari
        WHERE
                id_stilist = p_id_stilist
            AND trunc(ora_programare) = trunc(p_zi)
        FOR UPDATE;

    BEGIN
        FOR v_rec IN c_programari LOOP
            BEGIN
                v_stilist_nou := func_cauta_stilist_liber(v_rec.id_serviciu, v_rec.ora_programare, p_id_stilist);
                UPDATE programari
                SET
                    id_stilist = v_stilist_nou
                WHERE
                    id_programare = v_rec.id_programare;

                dbms_output.put_line('Programarea '
                                     || v_rec.id_programare
                                     || ' reasignata stilistului '
                                     || v_stilist_nou);
            EXCEPTION
                WHEN OTHERS THEN
                    DELETE FROM programari
                    WHERE
                        id_programare = v_rec.id_programare;

                    dbms_output.put_line('Programarea '
                                         || v_rec.id_programare
                                         || ' stearsa — niciun stilist disponibil');
            END;
        END LOOP;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            raise_application_error(-20001, 'Eroare la modificare programari: ' || sqlerrm);
    END;

END package_programari;
/

